  import java.util.Map;
  import sailpoint.object.Identity;
  import sailpoint.api.IdentityService;
  import sailpoint.tools.Util;
  import org.apache.log4j.Logger;

  Logger logger = Logger.getLogger("ascension.rules.AssignmentRule.gsuite");
  
  String userValidForRole = false;
  
  if (!identity.isInactive()){
    IdentityService is = new IdentityService();
    List appLinks = is.getLinks(identity, "GSuite");
    if (null != appLinks && !appLinks.isEmpty()) {
      for (Link lnk : appLinks) {
        Object value = lnk.getAttribute("groups");
        
        if(null!=value){
          List groupsList = new ArrayList();
          if(value instanceof String){
            groupsList.add(value);
          } else if(value instanceof List){
            groupsList.addAll(value);
          }

          if(null!=groupsList && groupsList.contains("MIROC-DL-Crittenton Everyone add on mailboxes")){
            userValidForRole = true;
          }
        }
      }
    }
  }

  return userValidForRole;
